    const migrationDb = getMigrationDatabase();

    // Create a temporary Drizzle instance for the migration
    const migrationSchema = /* import your schema */;
    const migrationDbInstance = drizzle(migrationDb, { schema: migrationSchema });

    migrate(migrationDbInstance, { 
        migrationsFolder: new URL("../../drizzle", import.meta.url).pathname
    });
}
```

