import Database from "better-sqlite3";
import { drizzle } from "drizzle-orm/better-sqlite3";
import * as schema from "./schema.js";

const sqlite = new Database(resolvedPath);   // unchanged
sqlite.pragma("journal_mode = WAL");          // unchanged
sqlite.pragma("foreign_keys = ON");           // unchanged

export const db = drizzle(sqlite, { schema }); // unchanged

/**
 * Runs `fn` with SQLite foreign-key enforcement disabled for this connection.
 * The pragma is toggled OUTSIDE any transaction (SQLite silently ignores it
 * inside one). Restores the previous state — even if `fn` throws.
 *
 * Callers must ensure no transaction is open on `sqlite` when this is called.
 */
export function withForeignKeysDisabled(fn: () => void): void {
    // PRAGMA foreign_keys returns [{foreign_keys: 0|1}] in better-sqlite3
    const [{ foreign_keys: prior }] = sqlite
        .pragma("foreign_keys") as [{ foreign_keys: number }];
    sqlite.pragma("foreign_keys = OFF");
    try {
        fn();
    } finally {
        sqlite.pragma(`foreign_keys = ${prior === 1 ? "ON" : "OFF"}`);
    }
}
```

